create table if not exists public.workflow_definitions (id uuid primary key default gen_random_uuid(), workflow_key text not null, version int not null, definition jsonb not null, created_at timestamptz not null default now(), unique(workflow_key, version));
create table if not exists public.workflow_runs (id uuid primary key default gen_random_uuid(), workflow_key text not null, tenant_id text not null, state text not null, correlation_id text not null, trace_id text not null, created_at timestamptz not null default now());
create table if not exists public.workflow_steps (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), step_key text not null, state text not null, attempt int not null default 0, created_at timestamptz not null default now());
create table if not exists public.workflow_approvals (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), approver_ref text not null, status text not null default 'pending', created_at timestamptz not null default now());
create table if not exists public.workflow_replays (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), requested_by text not null, created_at timestamptz not null default now());
create table if not exists public.workflow_failures (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), step_key text not null, error text not null, created_at timestamptz not null default now());
